import retrofit2.http.*
import com.example.radiation.data.models.*

/**
 * API сервіс для Radiation Monitoring System
 * Взято з Swagger документації
 * 
 * Адмін endpoints видалені - адмінка буде на вебі
 */
interface ApiService {

    // ============ AUTH ============

    @POST("auth/register")
    suspend fun register(@Body request: RegisterRequest): RegisterResponse

    @POST("auth/login")
    suspend fun login(@Body request: LoginRequest): LoginResponse

    @POST("auth/logout")
    suspend fun logout()

    @GET("auth/users/{id}")
    suspend fun getUserById(@Path("id") id: String): User

    // ============ DEVICES ============

    @GET("devices")
    suspend fun getDevices(): DeviceListResponse

    @POST("devices")
    suspend fun createDevice(@Body request: CreateDeviceRequest): CreateDeviceResponse

    @GET("devices/{id}")
    suspend fun getDeviceById(@Path("id") id: String): Device

    @PUT("devices/{id}")
    suspend fun updateDevice(
        @Path("id") id: String,
        @Body request: UpdateDeviceRequest
    ): Device

    @DELETE("devices/{id}")
    suspend fun deleteDevice(@Path("id") id: String): SuccessResponse

    // ============ SENSOR READINGS ============

    @POST("readings")
    suspend fun submitReading(@Body request: CreateReadingRequest): SuccessResponse

    @GET("readings")
    suspend fun getReadings(
        @Query("device_id") deviceId: String? = null,
        @Query("limit") limit: Int = 100,
        @Query("since") since: String? = null
    ): ReadingsListResponse

    // ============ ALERTS ============

    @GET("alerts")
    suspend fun getAlerts(
        @Query("level") level: String? = null,
        @Query("acknowledged") acknowledged: Boolean? = null
    ): AlertsListResponse

    @GET("alerts/{id}")
    suspend fun getAlertById(@Path("id") id: String): Alert

    @POST("alerts/{id}/ack")
    suspend fun acknowledgeAlert(@Path("id") id: String): SuccessResponse

    // ============ SUBSCRIPTIONS ============

    @POST("subscriptions")
    suspend fun createSubscription(@Body request: CreateSubscriptionRequest): Subscription

    @GET("subscriptions")
    suspend fun getSubscriptions(): SubscriptionsListResponse

    @DELETE("subscriptions/{id}")
    suspend fun deleteSubscription(@Path("id") id: String): SuccessResponse

    @PUT("subscriptions/{id}")
    suspend fun updateSubscription(
        @Path("id") id: String,
        @Body request: UpdateSubscriptionRequest
    ): Subscription
}

package com.example.radiation.di

import android.content.Context
import androidx.datastore.core.DataStore
import androidx.datastore.preferences.core.Preferences
import androidx.room.Room
import dagger.Module
import dagger.Provides
import dagger.hilt.InstallIn
import dagger.hilt.android.qualifiers.ApplicationContext
import dagger.hilt.components.SingletonComponent
import com.example.radiation.db.data.AppDb
import com.example.radiation.db.DbRepository
import com.example.radiation.db.DbRepositoryImpl
import com.example.radiation.repository.MainRepository
import com.example.radiation.repository.auth.AuthRepository
import com.example.radiation.repository.auth.AuthRepositoryImpl
import com.example.radiation.repository.device.DeviceRepository
import com.example.radiation.repository.device.DeviceRepositoryImpl
import com.example.radiation.repository.reading.ReadingRepository
import com.example.radiation.repository.reading.ReadingRepositoryImpl
import com.example.radiation.repository.alert.AlertRepository
import com.example.radiation.repository.alert.AlertRepositoryImpl
import com.example.radiation.repository.subscription.SubscriptionRepository
import com.example.radiation.repository.subscription.SubscriptionRepositoryImpl
import com.example.radiation.repository.computed.ComputedRepository
import com.example.radiation.repository.computed.ComputedRepositoryImpl
import com.example.radiation.network.ApiService
import com.example.radiation.config.Common
import javax.inject.Singleton

/**
 * Hilt модуль для Database та Repository конфігурації
 */
@Module
@InstallIn(SingletonComponent::class)
object RepositoryModule {

    @Singleton
    @Provides
    fun provideAppDb(
        @ApplicationContext context: Context
    ): AppDb {
        return Room.databaseBuilder(
            context,
            AppDb::class.java,
            Common.DATABASE_NAME
        ).build()
    }

    @Singleton
    @Provides
    fun provideDbRepository(
        appDb: AppDb
    ): DbRepository {
        return DbRepositoryImpl(appDb)
    }

    // ============ AUTH REPOSITORY ============
    @Singleton
    @Provides
    fun provideAuthRepository(
        apiService: ApiService,
        dataStore: DataStore<Preferences>
    ): AuthRepository {
        return AuthRepositoryImpl(apiService, dataStore)
    }

    // ============ DEVICE REPOSITORY ============
    @Singleton
    @Provides
    fun provideDeviceRepository(
        apiService: ApiService
    ): DeviceRepository {
        return DeviceRepositoryImpl(apiService)
    }

    // ============ READING REPOSITORY ============
    @Singleton
    @Provides
    fun provideReadingRepository(
        apiService: ApiService
    ): ReadingRepository {
        return ReadingRepositoryImpl(apiService)
    }

    // ============ ALERT REPOSITORY ============
    @Singleton
    @Provides
    fun provideAlertRepository(
        apiService: ApiService
    ): AlertRepository {
        return AlertRepositoryImpl(apiService)
    }

    // ============ SUBSCRIPTION REPOSITORY ============
    @Singleton
    @Provides
    fun provideSubscriptionRepository(
        apiService: ApiService
    ): SubscriptionRepository {
        return SubscriptionRepositoryImpl(apiService)
    }

    // ============ COMPUTED REPOSITORY ============
    @Singleton
    @Provides
    fun provideComputedRepository(
        apiService: ApiService
    ): ComputedRepository {
        return ComputedRepositoryImpl(apiService)
    }

    // ============ MAIN REPOSITORY (Facade) ============
    @Singleton
    @Provides
    fun provideMainRepository(
        authRepository: AuthRepository,
        deviceRepository: DeviceRepository,
        readingRepository: ReadingRepository,
        alertRepository: AlertRepository,
        subscriptionRepository: SubscriptionRepository,
        computedRepository: ComputedRepository
    ): MainRepository {
        return MainRepository(
            authRepository,
            deviceRepository,
            readingRepository,
            alertRepository,
            subscriptionRepository,
            computedRepository
        )
    }
}

